import os
import boto3
from botocore.exceptions import NoCredentialsError, ClientError
import joblib

def load_latest_model_from_s3():
    try:
        s3_client = boto3.client('s3')
        model_path = os.getenv('MODEL_PATH')
        if not model_path:
            raise ValueError("MODEL_PATH environment variable not set")

        bucket_name, prefix = model_path.split('/', 1)
        response = s3_client.list_objects_v2(Bucket=bucket_name, Prefix=prefix)
        
        if 'Contents' not in response:
            raise FileNotFoundError("No models found in the specified path")

        latest_model = max(response['Contents'], key=lambda x: x['LastModified'])
        model_key = latest_model['Key']

        local_model_path = '/tmp/' + os.path.basename(model_key)
        s3_client.download_file(bucket_name, model_key, local_model_path)

        model = joblib.load(local_model_path)
        return model

    except (NoCredentialsError, ClientError) as e:
        raise RuntimeError("Failed to load model from S3: " + str(e))

if __name__ == "__main__":
    model = load_latest_model_from_s3()
